        return -epsilon * (
            (-12 * sigma**12 / r**13) + (6 * sigma**6 / r**7)
        )

    r = torch.linspace(0.5, 2 * sigma, steps=100, requires_grad=True, device=device)
    drs = torch.outer(r, torch.tensor([1.0, 0, 0], device=device))
